def complex(x)
  r = 0
  if x > 0 then r += 1 end
  if x > 1 then r += 1 end
  if x > 2 then r += 1 end
  if x > 3 then r += 1 end
  if x > 4 then r += 1 end
  if x > 5 then r += 1 end
  if x > 6 then r += 1 end
  if x > 7 then r += 1 end
  if x > 8 then r += 1 end
  if x > 9 then r += 1 end
  if x > 10 then r += 1 end
  if x > 11 then r += 1 end
  if x > 12 then r += 1 end
  if x > 13 then r += 1 end
  if x > 14 then r += 1 end
  if x > 15 then r += 1 end
  r
end
